# ── 거래(특이거래) — 필터·정렬·지역 분류 ────────────────────────
_SEOUL_GU = {d["n"] for d in _GEO if d["sd"] == "seoul"}


_GG_SI = {d["n"] for d in _GEO if d["sd"] == "gg"}


def _region_of(gu):
    """단지 지역명(구/시)을 서울/경기로 분류. 못 찾으면 None."""
    if any(n in gu for n in _SEOUL_GU):
        return "seoul"
    if any(n in gu for n in _GG_SI):
        return "gg"
    return None
